import React, {type ReactNode, useImperativeHandle, useRef, useState} from 'react';
import {FiMenu, FiMoon, FiSun} from 'react-icons/fi';
import {BreadCrumb, Button, Flex} from "../../_compat";
import {classNames} from "primereact/utils";
import {Menu} from 'primereact/menu';
import {Avatar} from 'primereact/avatar';
import LanguageSwitcher from "./LangButton";
import {Icon, useKitsConcerto, useKitsTheme, useLanguage} from "../../_compat";
import type {RouteObject} from "react-router-dom";

interface IHeader {
    setHide: (hide: boolean) => void;
    hide: boolean;
    ref?: React.Ref<IHeaderRef>;
    routes: RouteObject[]
}

export interface IHeaderRef {
    appendToHeader: (element: ReactNode) => void
}

const Header = ({setHide, hide, ref, routes}: IHeader) => {
    const [children, setChildren] = useState<ReactNode>();
    const openMenu = useRef<Menu>(null);
    const {onLogOut, menuItems, userAvatar} = useKitsConcerto();
    const {colorMode, toggleColorMode, resolveToken} = useKitsTheme();
    const {t} = useLanguage();

    const appendToHeader = (element: ReactNode) => {
        setChildren(element);
    };

    useImperativeHandle(ref, () => ({appendToHeader}), []);

    const isDark = colorMode === 'dark';
    const surfaceCard = resolveToken('surface-card');
    const borderColor = resolveToken('border');
    const textSecondary = resolveToken('text-secondary');
    const primaryColor = resolveToken('primary');

    return (
        <Flex
            w={'full'}
            px={16}
            py={8}
            justifyContent={['space-between', 'space-between', 'flex-end', 'flex-end', 'flex-end']}
            alignItems={'center'}
            gap={8}
            className={'card'}
        >
            {/* Mobile hamburger */}
            <Button
                style={{display: ['flex', 'flex', 'flex', 'flex', 'none']}}
                rounded
                aria-label={t('openMenu')}
                icon={<FiMenu size={20}/>}
                onClick={() => setHide(true)}
            />

            <BreadCrumb/>

            {/* Injected children slot */}
            <Flex flex={1} px={8}>
                {children}
            </Flex>

            {/* Action buttons */}
            <Flex alignItems={'center'} gap={4}>
                {/* Color mode toggle */}
                <Button
                    rounded
                    aria-label={t('toggleColorMode')}
                    onClick={toggleColorMode}
                    icon={isDark ? <Icon name={'sun'} size={'sm'} color={'white'}/> :<Icon name={'moon'} size={'sm'}  color={'white'}/>}
                    style={{
                        width: 30,
                        height: 30,
                    }}
                />

                {/* User menu trigger */}
                <Flex
                    alignItems={'center'}
                    onClick={(event) => openMenu.current?.toggle(event)}
                    cursor={'pointer'}
                >
                    <Menu
                        model={[
                            ...(menuItems ?? []),
                            {
                                template: (_item: any, options: any) => (
                                    <Flex p={10} flexDirection={'column'} gap={10}>
                                        <Button
                                            onClick={(e) => onLogOut ? onLogOut() : options.onClick(e)}
                                            icon="pi pi-sign-out"
                                            className={classNames(options.className, 'w-full flex align-items-center')}
                                            label={t('signOut')}
                                            severity="danger"
                                        />
                                    </Flex>
                                ),
                            },
                            {separator: true},
                            {
                                template: () => (
                                    <Flex p={10} justifyContent={'center'}>
                                        <LanguageSwitcher/>
                                    </Flex>
                                ),
                            },
                        ]}
                        popup
                        ref={openMenu}
                        id="popup_menu_right"
                        popupAlignment="right"
                        style={{
                            width: '18rem',
                            backgroundColor: surfaceCard,
                            borderColor: borderColor,
                            borderRadius: '12px',
                            overflow: 'hidden',
                            padding: 0,
                            border: `1px solid ${borderColor}`,
                            boxShadow: isDark
                                ? '0 8px 32px rgba(0, 0, 0, 0.5), 0 2px 8px rgba(0, 0, 0, 0.3)'
                                : '0 8px 32px rgba(0, 0, 0, 0.12), 0 2px 8px rgba(0, 0, 0, 0.06)',
                        }}
                    />
                    {userAvatar?.image ? (
                        <Avatar
                            image={userAvatar.image}
                            shape="circle"
                            aria-controls="popup_menu_right"
                            aria-haspopup
                            style={{
                                width: 30,
                                height: 30,
                                cursor: 'pointer',
                            }}
                        />
                    ) : (
                        <Avatar
                            label={userAvatar?.label || '?'}
                            shape="circle"
                            aria-controls="popup_menu_right"
                            aria-haspopup
                            style={{
                                width: 30,
                                height: 30,
                                backgroundColor: userAvatar?.color || primaryColor,
                                color: '#FFFFFF',
                                fontWeight: 600,
                                fontSize: '14px',
                                cursor: 'pointer',
                            }}
                        />
                    )}
                </Flex>
            </Flex>
        </Flex>
    );
};

export default Header;
